import { useRef, useState, useEffect } from "react";
import { useGamepad } from "../hooks/useGamepad";
import { hexToRgba, STICK_COLORS } from "../lib/controllerLayout";
import { LAYOUTS, ControllerType } from "../lib/layouts";
import { ControllerConfig, LayoutOverrides } from "../types/config";
import { LayoutEditor } from "./LayoutEditor";
import { BodyEffectOverlay } from "./BodyEffectOverlay";
import { RgbBodyCanvas } from "./RgbBodyCanvas";
import { WATERMARK_DATA_URL } from "../lib/watermarkData";
import { isVideoSkin } from "./SkinPanel";

interface Props {
  config: ControllerConfig;
  overrides: LayoutOverrides;
  showButtonLabels: boolean;
  editMode?: boolean;
  onOverridesChange?: (o: LayoutOverrides) => void;
}

export function ControllerPreview({ config, overrides, showButtonLabels, editMode, onOverridesChange }: Props) {
  const gp = useGamepad();
  const containerRef = useRef<HTMLDivElement>(null);

  // Track the container's rendered CSS size so we can compute mask scaling
  const [cssSize, setCssSize] = useState({ w: 0, h: 0 });
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    // Read size immediately on mount, then watch for changes
    const rect = el.getBoundingClientRect();
    if (rect.width > 0) setCssSize({ w: rect.width, h: rect.height });
    const ro = new ResizeObserver((entries) => {
      const { width, height } = entries[0].contentRect;
      if (width > 0) setCssSize({ w: width, h: height });
    });
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  const baseLayout = LAYOUTS[config.controllerType] ?? LAYOUTS["c4d1"];

  const buttons = baseLayout.buttons.map((b) => ({
    ...b,
    ...(overrides.buttons[b.index] ?? {}),
  }));
  const sticks = baseLayout.sticks.map((s, i) => ({
    ...s,
    ...(overrides.sticks[i] ?? {}),
  }));

  const lStick = sticks[0];
  const rStick = sticks[1];
  const lx = gp.axes[lStick.axisX] ?? 0;
  const ly = gp.axes[lStick.axisY] ?? 0;
  const rx = gp.axes[rStick.axisX] ?? 0;
  const ry = gp.axes[rStick.axisY] ?? 0;

  const ltLabel = config.controllerType === "c4d1" ? "LT" : "L2";
  const rtLabel = config.controllerType === "c4d1" ? "RT" : "R2";

  // Compute how the controller skin renders inside the container (background-size: contain)
  const { skinWidth, skinHeight } = baseLayout;
  const { w: cW, h: cH } = cssSize;
  const scale = cW > 0 && cH > 0 ? Math.min(cW / skinWidth, cH / skinHeight) : 0;
  const renderedImgW = skinWidth * scale;   // mask image rendered width in CSS px
  const renderedImgH = skinHeight * scale;  // mask image rendered height in CSS px

  // For each mask button we position the wrapper div at btn.x%, btn.y%
  // and compute mask-position so the button shape from the template is
  // always centred inside the wrapper — regardless of where the wrapper is dragged.
  function maskStyle(btn: typeof buttons[number], hPct: number, maskUrl: string, maskCx: number, maskCy: number) {
    if (scale === 0) return {};   // wait for first ResizeObserver tick
    const elW = (btn.size / 100) * cW;   // element width in CSS px
    const elH = (hPct   / 100) * cH;    // element height in CSS px
    // Offset the mask image so the button's shape centre aligns with the element centre
    const mpX = elW / 2 - (maskCx / 100) * renderedImgW;
    const mpY = elH / 2 - (maskCy / 100) * renderedImgH;
    return {
      WebkitMaskImage: `url(${maskUrl})`,
      maskImage: `url(${maskUrl})`,
      WebkitMaskSize: `${renderedImgW}px ${renderedImgH}px`,
      maskSize: `${renderedImgW}px ${renderedImgH}px`,
      WebkitMaskPosition: `${mpX}px ${mpY}px`,
      maskPosition: `${mpX}px ${mpY}px`,
      WebkitMaskRepeat: "no-repeat",
      maskRepeat: "no-repeat",
    };
  }

  return (
    <div
      ref={containerRef}
      className="relative w-full"
      style={{ aspectRatio: `${baseLayout.skinWidth}/${baseLayout.skinHeight}` }}
    >
      {/* Blur wrapper — blurs all controller content when disconnected */}
      <div style={{
        position: "absolute", inset: 0,
        filter: !gp.connected && !editMode ? "blur(4px)" : "none",
        transition: "filter 0.4s ease",
        pointerEvents: !gp.connected && !editMode ? "none" : "auto",
      }}>
      {/* Drop shadow — a standalone silhouette layer rendered BEHIND both the RGB
          glow and the controller art. Previously this was a `filter: drop-shadow()`
          on the same layer as the controller art; since that layer paints above
          the RGB glow in stacking order, the dark shadow silhouette was compositing
          directly over the glow and dimming it heavily. Rendering the shadow as its
          own bottom-most layer keeps it fully independent of the RGB glow. */}
      {config.showShadow && config.controllerSkin && (() => {
        const rad = (config.shadowAngle * Math.PI) / 180;
        const dist = 16;
        const x = Math.round(Math.sin(rad) * dist);
        const y = Math.round(-Math.cos(rad) * dist);
        const a = config.shadowIntensity;
        const layers: React.CSSProperties[] = [
          { filter: "brightness(0) blur(24px)", opacity: a,              transform: `translate(${x}px,${y}px)` },
          { filter: "brightness(0) blur(8px)",  opacity: Math.min(a+0.1,1), transform: `translate(${Math.round(x*0.4)}px,${Math.round(y*0.4)}px)` },
        ];
        return layers.map((layerStyle, i) => (
          isVideoSkin(config.controllerSkin) ? (
            <video key={i} src={config.controllerSkin} autoPlay loop={config.controllerSkinLoop} muted playsInline
              style={{ position:"absolute", inset:0, width:"100%", height:"100%",
                objectFit: config.controllerSkinVideoFit ?? "contain", pointerEvents:"none", ...layerStyle }} />
          ) : (
            <div key={i} style={{ position:"absolute", inset:0, width:"100%", height:"100%", pointerEvents:"none",
              background:`url("${config.controllerSkin}") center/contain no-repeat`, ...layerStyle }} />
          )
        ));
      })()}

      {/* Black backdrop — same silhouette mask as the RGB layer below, filled
          solid black so there's no transparency showing through behind the
          RGB glow (mirrors the mouse/keyboard RGB backdrop treatment). */}
      {config.rgbBodyEnabled && baseLayout.bodyMaskUrl && (
        <div className="absolute inset-0 w-full h-full pointer-events-none" style={{
          background: "#000",
          WebkitMaskImage: `url("${baseLayout.bodyMaskUrl}")`,
          maskImage: `url("${baseLayout.bodyMaskUrl}")`,
          WebkitMaskSize: "contain", maskSize: "contain",
          WebkitMaskPosition: "center", maskPosition: "center",
          WebkitMaskRepeat: "no-repeat", maskRepeat: "no-repeat",
        }} />
      )}

      {/* RGB body silhouette — sits behind the controller art, controller-body-only mask (no triggers) */}
      {config.rgbBodyEnabled && baseLayout.bodyMaskUrl && (
        <RgbBodyCanvas
          maskUrl={baseLayout.bodyMaskUrl}
          speed={config.rgbBodySpeed}
          mode={config.rgbBodyMode}
          intensity={config.rgbBodyIntensity}
          color={config.rgbBodyMode === "breathing" ? config.rgbBodyBreathingColor : config.rgbBodyWaveColor}
          rainbow={config.rgbBodyMode === "breathing" ? config.rgbBodyBreathingRainbow : config.rgbBodyWaveRainbow}
        />
      )}


      {/* Controller background */}
      <div className="absolute inset-0">
        {isVideoSkin(config.controllerSkin) ? (
          (() => {
            return (
              /* Color correction goes on the wrapper, NOT the video element.
                 Applying CSS filter directly to <video> causes Chrome to composite
                 the video onto a white offscreen buffer before filtering, washing
                 out all the colors. The wrapper approach keeps the video clean.
                 Shadow is rendered separately above (see the dedicated shadow layer)
                 so it can't interfere with the RGB glow's stacking. */
              <div style={{
                position: "relative",
                width: "100%", height: "100%",
                filter: [
                  config.controllerSkinContrast !== 1 ? `contrast(${config.controllerSkinContrast})` : "",
                  config.controllerSkinSaturate !== 1 ? `saturate(${config.controllerSkinSaturate})` : "",
                ].filter(Boolean).join(" ") || undefined,
              }}>
                <video
                  src={config.controllerSkin}
                  autoPlay
                  loop={config.controllerSkinLoop}
                  muted
                  playsInline
                  style={{
                    width: "100%", height: "100%",
                    objectFit: config.controllerSkinVideoFit ?? "contain",
                    display: "block",
                    background: "transparent",
                  }}
                />

              </div>
            );
          })()
        ) : (
          <div
            className="absolute inset-0"
            style={{
              background: config.controllerSkin
                ? `url("${config.controllerSkin}") center/contain no-repeat`
                : undefined,
            }}
          >

            {!config.controllerSkin && (
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="text-center text-muted-foreground">
                  <div className="text-5xl mb-2 opacity-20">🎮</div>
                  <p className="text-sm opacity-50">Upload a controller skin</p>
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Animated body effect — masked to the controller skin's silhouette.
          Disabled when a WebM video skin is active (CSS mask-image can't use video). */}
      {config.bodyEffect !== "none" && config.controllerSkin && !isVideoSkin(config.controllerSkin) && (
        <BodyEffectOverlay
          effect={config.bodyEffect}
          speed={config.bodyEffectSpeed}
          intensity={config.bodyEffectIntensity}
          maskUrl={config.controllerSkin}
          glowColor={(config.bodyEffect === "fire" || config.bodyEffect === "reactiveFire") ? config.fireColor1 : config.pulseGlowColor}
          fireColor2={config.fireColor2}
          fireGlowSpeed={config.fireGlowSpeed}
          fireEmberSpeed={config.fireEmberSpeed}
          reactiveColor={config.reactiveRippleColor}
          reactiveRainbow={config.reactiveRippleRainbow}
          pressedButtons={["reactive","reactiveReverse","particleBurst","reactiveFire"].includes(config.bodyEffect) ? new Set(
            gp.buttons.map((pressed, i) => pressed ? i : -1).filter(i => i >= 0)
          ) : undefined}
          buttonPositions={["reactive","reactiveReverse","particleBurst","reactiveFire"].includes(config.bodyEffect) ? (() => {
            const pos: Record<number, { x:number; y:number; size:number; shape:string; maskSw?:number; maskSh?:number; skinAspect?:number }> = {};
            const skinAspect = baseLayout.skinHeight / baseLayout.skinWidth;
            buttons.forEach(b => {
              const mask = baseLayout.buttonMasks?.[b.index];
              pos[b.index] = {
                x: b.x, y: b.y, size: b.size, shape: b.shape,
                ...(b.shape === "rect" && mask ? { maskSw: mask.sw, maskSh: mask.sh, skinAspect } : {}),
              };
            });
            sticks.forEach(s => { pos[s.pressBtn] = { x: s.x, y: s.y, size: s.size, shape: "circle" }; });
            return pos;
          })() : undefined}
        />
      )}

      {/* Button overlays - DEBUG: always visible in edit mode */}
      {buttons.map((btn) => {
        const isLt = btn.index === 6;
        const isRt = btn.index === 7;
        const isTrigger = isLt || isRt;
        const pressed = gp.buttons[btn.index] ?? false;
        const maskDef = baseLayout.buttonMasks[btn.index];

        // Opacity: live only in preview, faint guide in edit mode
        let activeOpacity = 0;
        if (editMode) {
          activeOpacity = 0; // completely hide in edit mode - LayoutEditor handles markers
        } else if (isTrigger) {
          const tv = isLt ? (gp.triggers[0] ?? 0) : (gp.triggers[1] ?? 0);
          activeOpacity = tv * config.buttonOpacity;
        } else {
          activeOpacity = pressed ? config.buttonOpacity : 0;
        }

        const effectiveColor = config.usePerButtonColors
          ? (baseLayout.buttonColors[btn.index] ?? config.buttonColor)
          : config.buttonColor;

        // Height for pill/rect shapes
        const hPct = btn.shape === "pill-h" || btn.shape === "rect" ? btn.size * 0.45 : btn.size;

        // Inner fade: for mask buttons the shape is centred in the element, so gradient at 50%/50%
        const gradCx = maskDef ? 50 : 50;
        const gradCy = maskDef ? 50 : 50;
        const bg = config.innerFade
          ? `radial-gradient(circle at ${gradCx}% ${gradCy}%, ${effectiveColor} 0%, ${hexToRgba(effectiveColor, 0.5)} 45%, transparent 100%)`
          : effectiveColor;

        const outerGlowFilter = config.outerFade
          ? ` drop-shadow(0 0 ${config.glowSize * 2}px ${hexToRgba(effectiveColor, 0.35)})`
          : "";
        const innerFadeFilter = config.innerFade
          ? ` brightness(1.25)`
          : "";
        const glowFilter = (!editMode && config.glowEnabled && activeOpacity > 0.01)
          ? `drop-shadow(0 0 ${config.glowSize}px ${hexToRgba(effectiveColor, 0.9)})${outerGlowFilter}${innerFadeFilter}`
          : "none";

        const transitionProp = editMode
          ? "none"
          : isTrigger
          ? "opacity 0.06s linear, filter 0.06s linear"
          : "opacity 0.04s, filter 0.04s";

        const borderRadius =
          btn.shape === "circle" || btn.shape.startsWith("cross")
            ? "50%"
            : btn.shape === "rect"
            ? "8px"
            : "9999px";

        // Natural size from shape pixel bounds
        const natW = maskDef ? (maskDef.sw / 100) * renderedImgW / cW * 100 : btn.size;
        const natH = maskDef ? (maskDef.sh / 100) * renderedImgH / cH * 100 : hPct;

        // Apply overrides from editor — position and size move together
        const btnOverride = overrides.buttons[btn.index];
        const defaultX = maskDef ? maskDef.cx : btn.x;
        const defaultY = maskDef ? maskDef.cy : btn.y;
        const posX = btnOverride?.x !== undefined ? btnOverride.x : defaultX;
        const posY = btnOverride?.y !== undefined ? btnOverride.y : defaultY;
        const finalW = btnOverride?.size !== undefined ? btnOverride.size : natW;
        const finalH = natH * (finalW / natW);

        // Mask: skin image at natural scale, offset so shape centre = element centre
        // Use cropped mask — fills element exactly, scales perfectly
        const croppedUrl = maskDef?.url.replace("masks/", "masks-cropped/");
        const mStyle: React.CSSProperties = maskDef
          ? {
              WebkitMaskImage: `url(${croppedUrl})`,
              maskImage: `url(${croppedUrl})`,
              WebkitMaskSize: "100% 100%",
              maskSize: "100% 100%",
              WebkitMaskPosition: "center",
              maskPosition: "center",
              WebkitMaskRepeat: "no-repeat",
              maskRepeat: "no-repeat",
            }
          : {};

        return (
          <div
            key={btn.index}
            className="absolute pointer-events-none"
            style={{
              left: `${posX}%`,
              top: `${posY}%`,
              width: `${finalW}%`,
              height: `${finalH}%`,
              transform: "translate(-50%, -50%)",
              opacity: activeOpacity,
              filter: glowFilter,
              transition: transitionProp,
            }}
          >
            {/* Stroke layer: slightly enlarged duplicate mask behind, creates a smooth outline */}
            {config.strokeEnabled && (
              <div
                className="absolute"
                style={{
                  inset: `-${config.strokeWidth}px`,
                  borderRadius: maskDef ? undefined : borderRadius,
                  background: config.strokeColor || "#ffffff",
                  ...mStyle,
                }}
              />
            )}
            <div
              className="absolute inset-0"
              style={{
                borderRadius: maskDef ? undefined : borderRadius,
                background: bg,
                ...mStyle,
              }}
            />
            {/* Label only shown for geometric (non-mask) buttons when labels are on */}
            {showButtonLabels && !maskDef && (
              <span
                className="absolute inset-0 flex items-center justify-center font-bold select-none"
                style={{ fontSize: "clamp(5px,1%,9px)", color: "#000", mixBlendMode: "multiply" }}
              >
                {btn.label}
              </span>
            )}
          </div>
        );
      })}

      {/* Sticks — zone IS the button press; tilt on axis movement */}
      {sticks.map((stick, i) => {
        const ax = gp.axes[stick.axisX] ?? 0;
        const ay = gp.axes[stick.axisY] ?? 0;
        const pressed = gp.buttons[stick.pressBtn] ?? false;
        const stickSkin = i === 0 ? config.leftStickSkin : config.rightStickSkin;
        const stickAlt = i === 0 ? "LS" : "RS";
        // Stick-specific color (left/right, optionally linked)
        const stickColor = i === 0
          ? config.leftStickColor
          : (config.linkStickColors ? config.leftStickColor : config.rightStickColor);

        // Axis tilt: rotate toward the direction of stick deflection
        const tiltAmount = 18; // degrees max tilt
        const tiltX = -ay * tiltAmount; // tilt forward/back
        const tiltY = ax * tiltAmount;  // tilt left/right

        // Press glow — layered box-shadow on its own sibling div, fully isolated
        // from the drop shadow. Intensity controls opacity of each layer; size
        // controls spread distance — both scale together for a real glow look.
        const glowSize = config.stickGlowSize ?? 8;
        const glowInt = config.stickGlowEnabled ? (config.stickGlowIntensity ?? 0.85) : 0;
        const pressBoxShadow = pressed
          ? `0 0 4px 2px rgba(255,255,255,${0.9 * glowInt}), `
            + `0 0 ${glowSize * 0.6}px ${glowSize * 0.6}px ${hexToRgba(stickColor, glowInt)}, `
            + `0 0 ${glowSize * 1.4}px ${glowSize * 1.4}px ${hexToRgba(stickColor, glowInt * 0.6)}, `
            + `0 0 ${glowSize * 2.4}px ${glowSize * 2}px ${hexToRgba(stickColor, glowInt * 0.3)}`
          : undefined;

        // Drop shadow — lives on its own div; completely separate from the glow.
        const shadowAngleRad = ((config.stickShadowAngle ?? 135) * Math.PI) / 180;
        const shadowDist = config.stickShadowDistance ?? 10;
        const sdx = Math.sin(shadowAngleRad) * shadowDist;
        const sdy = Math.cos(shadowAngleRad) * shadowDist;
        const stickBoxShadow = (config.stickShadowEnabled ?? true)
          ? `${sdx}px ${sdy}px ${shadowDist * 1.8}px rgba(0,0,0,${config.stickShadowIntensity ?? 0.65}), ${sdx * 0.4}px ${sdy * 0.4}px ${shadowDist * 0.6}px rgba(0,0,0,${Math.min((config.stickShadowIntensity ?? 0.65) + 0.15, 1)})`
          : undefined;

        return (
          <div
            key={i}
            className="absolute pointer-events-none"
            style={{
              left: `${stick.x}%`,
              top: `${stick.y}%`,
              width: `${stick.size}%`,
              height: `${stick.size * (cW / cH)}%`,
              transform: "translate(-50%, -50%)",
              perspective: "120px",
            }}
          >
            <div
              style={{
                width: "100%", height: "100%",
                transform: editMode
                  ? undefined
                  : `translate(${ax * (config.stickTravel / 1280) * cW}px, ${ay * (config.stickTravel / 1280) * cW}px) rotateX(${tiltX}deg) rotateY(${tiltY}deg)`,
                transition: "transform 0.04s ease-out",
                transformStyle: "preserve-3d",
                position: "relative",
              }}
            >
              {/* Layer 1 — drop shadow (z 0). Separate div; no filter, no relation to glow. */}
              {stickBoxShadow && (
                <div style={{ position: "absolute", inset: 0, borderRadius: "50%", boxShadow: stickBoxShadow, zIndex: 0 }} />
              )}

              {/* Layer 2 — stick image, clipped to circle (z 1) */}
              <div style={{ position: "absolute", inset: 0, borderRadius: "50%", overflow: "hidden", zIndex: 1 }}>
                {stickSkin
                  ? <img src={stickSkin} alt={stickAlt} style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%", display: "block" }} />
                  : <div style={{ width: "100%", height: "100%", borderRadius: "50%", background: "rgba(255,255,255,0.1)", border: "1px solid rgba(255,255,255,0.2)" }} />
                }
              </div>

              {/* Layer 3 — rim highlight (z 2) */}
              {(config.stickHighlightEnabled ?? true) && (() => {
                const hCol = config.stickHighlightColor ?? "#ffffff";
                const hInt = config.stickHighlightIntensity ?? 0.35;
                return (
                  <div style={{
                    position: "absolute", inset: 0, borderRadius: "50%", pointerEvents: "none", zIndex: 2,
                    background: `radial-gradient(circle, transparent 52%, ${hexToRgba(hCol, hInt * 0.65)} 68%, ${hexToRgba(hCol, hInt)} 78%, transparent 90%)`,
                  }} />
                );
              })()}

              {/* Layer 4 — press glow (z 10). Completely independent sibling; uses box-shadow
                  not filter, so the drop shadow below cannot affect it in any way. */}
              {pressed && (
                <div style={{ position: "absolute", inset: 0, borderRadius: "50%", pointerEvents: "none", zIndex: 10, boxShadow: pressBoxShadow }} />
              )}
            </div>
          </div>
        );
      })}

      {/* Trigger bars moved to Studio.tsx, outside the preview box */}

      {/* Layout editor overlay (on top of button guides) */}
      {editMode && onOverridesChange && (
        <LayoutEditor
          layout={baseLayout}
          overrides={overrides}
          onOverridesChange={onOverridesChange}
          containerRef={containerRef}
          containerW={cW}
          containerH={cH}
        />
      )}

      {/* Connection status badge (preview only) */}
      {!editMode && (
        <div
          className={`absolute top-2 right-2 text-[9px] font-mono px-2 py-0.5 rounded-full border transition-all ${
            gp.connected
              ? "bg-emerald-500/20 text-emerald-400 border-emerald-500/30"
              : "bg-amber-500/20 text-amber-400 border-amber-500/30"
          }`}
        >
          {gp.connected 
            ? "● Connected - Press buttons to test"
            : `○ ${baseLayout.connectMessage} - Press any button on controller`}
        </div>
      )}
      
      {/* Watermark overlay — green screen keyed via canvas. Lives inside the
          blur wrapper so it blurs along with everything else when
          disconnected, and renders before the status box below so that box
          stacks on top of it rather than being covered. */}
      {config.showWatermark && !editMode && (
        <WatermarkOverlay controllerType={config.controllerType} />
      )}
      </div>{/* end blur wrapper */}

      {!gp.connected && !editMode && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div style={{
            background: "rgba(10,10,14,0.85)",
            border: "1px solid rgba(255,255,255,0.10)",
            borderRadius: "16px",
            padding: "22px 32px",
            backdropFilter: "blur(10px)",
            WebkitBackdropFilter: "blur(10px)",
            textAlign: "center",
            boxShadow: "0 8px 32px rgba(0,0,0,0.9), 0 2px 8px rgba(0,0,0,0.8), 0 0 0 1px rgba(255,255,255,0.06)",
            minWidth: "220px",
            marginBottom: config.controllerType === "c4d4" ? "10%" : ["c4d5","c4d5-edge"].includes(config.controllerType) ? "14%" : "0",
          }}>
            <img src="data:image/png;base64," alt="Customs4daez" style={{ width: "160px", marginBottom: "14px", display: "block", marginLeft: "auto", marginRight: "auto" }} />
            <p style={{ fontSize: "12px", fontWeight: 600, color: "rgba(255,255,255,0.9)", marginBottom: "5px" }}>
              No controller detected
            </p>
            <p style={{ fontSize: "10px", color: "rgba(255,255,255,0.45)" }}>
              Press any button on your controller
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

function WatermarkOverlay({ controllerType }: { controllerType: ControllerType }) {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const vid = videoRef.current;
    if (!vid) return;

    let timer: ReturnType<typeof setTimeout>;

    function playOnce() {
      vid!.currentTime = 0;
      vid!.play();
    }

    vid.onended = () => {
      // Wait 45 seconds after the video ends before playing again
      timer = setTimeout(playOnce, 15000);
    };

    // Start first play
    playOnce();

    return () => {
      clearTimeout(timer);
      vid.onended = null;
    };
  }, []);

  // Each controller body sits a little differently in frame, so the
  // watermark's vertical position is tuned per controller type rather than
  // using one fixed value for all of them.
  const watermarkTop =
    controllerType === "c4d1" || controllerType === "c4d1-edge" ? "12%"
    : controllerType === "c4d4" ? "7%"
    : "3%";

  return (
    <video
      ref={videoRef}
      src={WATERMARK_DATA_URL}
      muted
      playsInline
      style={{
        position: "absolute",
        top: watermarkTop,
        left: "50%",
        transform: "translateX(-50%)",
        width: "102%",
        pointerEvents: "none",
      }}
    />
  );
}
